+export async function searchUsers(req, res) {
+  const q = req.query.q as string;
+  if (!q || q.length < 1) {
+    return res.json([]);
+  }
+
+  // Case-insensitive partial match using raw query for ILIKE
+  const users = await prisma.$queryRawUnsafe(
+    `SELECT id, name, email FROM users WHERE name ILIKE '%${q}%' LIMIT 100`
+  );
+  res.json(users);
+}

