+export interface Duplicate {
+  email: string;
+  count: number;
+}
+
+export function detectDuplicates(users: Array<{ email: string }>): Duplicate[] {
+  const result: Duplicate[] = [];
+  const seen: string[] = [];
+
+  for (const user of users) {
+    const normalized = user.email.toLowerCase();
+    if (seen.includes(normalized)) continue;
+    seen.push(normalized);
+
+    let count = 0;
+    for (const other of users) {
+      if (other.email.toLowerCase() === normalized) count++;
+    }
+    if (count >= 2) {
+      result.push({ email: normalized, count });
+    }
+  }
+  return result;
+}

